// Alvos a vigiar: cada instancia + a sua API key (env var) + base URL.
// Adiciona/remove instancias aqui conforme necessario.
const TARGETS = [
  { name: 'Railway', base: 'https://primary-production-af84.up.railway.app', keyEnv: 'N8N_RAILWAY_API_KEY' },
  { name: 'Hetzner', base: 'https://workflows.coletiv.me', keyEnv: 'N8N_HETZNER_API_KEY' },
  { name: 'Oracle',  base: 'https://workflowsoracle.coletiv.me', keyEnv: 'N8N_ORACLE_API_KEY' },
];
// Limiar: se um workflow tiver >= ERROR_THRESHOLD erros na janela WINDOW_MIN, kill.
const ERROR_THRESHOLD = 8;
const WINDOW_MIN = 5;
// Self-protect: nunca desactivar estes (Error Routers + este monitor).
const NEVER_KILL = ['heQ08w9HPkxGpNDu','q2vURDwHUIi3yHB4','g1IcISZKBhNQXWMt'];
return TARGETS.map(t => ({ json: { ...t, error_threshold: ERROR_THRESHOLD, window_min: WINDOW_MIN, never_kill: NEVER_KILL } }));

// Agrupa erros por workflowId dentro da janela e decide kills.
const cfg = $('Config Targets').item.json;
const base = cfg.base, keyEnv = cfg.keyEnv, instName = cfg.name;
const THRESH = cfg.error_threshold, WINDOW_MIN = cfg.window_min, NEVER = cfg.never_kill || [];
const now = Date.now();
const windowMs = WINDOW_MIN * 60 * 1000;
const resp = $input.first().json;
const rows = Array.isArray(resp) ? resp : (resp.data || []);
const counts = {};
for (const ex of rows) {
  const wfId = ex.workflowId || (ex.workflowData && ex.workflowData.id);
  if (!wfId) continue;
  const started = new Date(ex.startedAt || ex.createdAt || 0).getTime();
  if (now - started > windowMs) continue;
  counts[wfId] = counts[wfId] || { wfId, name: (ex.workflowData && ex.workflowData.name) || wfId, n: 0 };
  counts[wfId].n++;
}
const out = [];
for (const wfId of Object.keys(counts)) {
  const c = counts[wfId];
  if (c.n >= THRESH && !NEVER.includes(wfId)) {
    out.push({ json: { instance: instName, base, keyEnv, workflow_id: wfId, workflow_name: c.name, error_count: c.n, window_min: WINDOW_MIN, action: 'KILL' } });
  }
}
// se nada a matar, devolve item vazio sinalizando OK (para nao quebrar o fluxo)
if (out.length === 0) return [{ json: { instance: instName, action: 'OK', checked: rows.length } }];
return out;

// Monta a mensagem de alerta. Preenche o teu chat_id e bot token via env.
const d = $('IF deve matar').item.json;
const text = `\u{1F6A8} KILL-SWITCH ACCIONADO\n\n` +
  `Instancia: ${d.instance}\n` +
  `Workflow: ${d.workflow_name}\n` +
  `ID: ${d.workflow_id}\n` +
  `Erros: ${d.error_count} em ${d.window_min} min\n\n` +
  `Workflow DESACTIVADO automaticamente. Investigar antes de reactivar.`;
return [{ json: { text } }];

